CREATE TABLE IF NOT EXISTS group_purchase_campaigns (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, campaign_name VARCHAR(160) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'OPEN', join_deadline DATE NOT NULL, min_total_qty INT NOT NULL);
CREATE TABLE IF NOT EXISTS group_purchase_participants (id BIGSERIAL PRIMARY KEY, campaign_id BIGINT NOT NULL REFERENCES group_purchase_campaigns(id), tenant_id BIGINT NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'JOINED');
CREATE TABLE IF NOT EXISTS group_purchase_items (id BIGSERIAL PRIMARY KEY, campaign_id BIGINT NOT NULL REFERENCES group_purchase_campaigns(id), product_id BIGINT NOT NULL, target_qty INT NOT NULL);
CREATE TABLE IF NOT EXISTS group_purchase_price_tiers (id BIGSERIAL PRIMARY KEY, campaign_id BIGINT NOT NULL REFERENCES group_purchase_campaigns(id), min_qty INT NOT NULL, unit_price NUMERIC(14,2) NOT NULL);
CREATE TABLE IF NOT EXISTS group_purchase_commitments (id BIGSERIAL PRIMARY KEY, campaign_id BIGINT NOT NULL REFERENCES group_purchase_campaigns(id), participant_id BIGINT NOT NULL REFERENCES group_purchase_participants(id), committed_qty INT NOT NULL);
CREATE TABLE IF NOT EXISTS group_purchase_results (id BIGSERIAL PRIMARY KEY, campaign_id BIGINT NOT NULL REFERENCES group_purchase_campaigns(id), reached_qty INT NOT NULL, final_unit_price NUMERIC(14,2), closed_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE OR REPLACE VIEW vw_group_purchase_progress AS SELECT c.id,c.campaign_name,c.status,c.min_total_qty,COALESCE(SUM(cm.committed_qty),0) committed_qty FROM group_purchase_campaigns c LEFT JOIN group_purchase_commitments cm ON cm.campaign_id=c.id GROUP BY c.id;
